# Simple log rotation script for TrackFraud
# Usage: ./rotate-logs.sh [max_size_mb] [keep_count]

MAX_SIZE_MB=${1:-100}
KEEP_COUNT=${2:-5}
LOGS_DIR="/Volumes/MacBackup/TrackFraudProject/logs"

echo "Rotating logs larger than ${MAX_SIZE_MB}MB..."

for logfile in "${LOGS_DIR}"/*.log; do
    if [ -f "$logfile" ]; then
        size_mb=$(du -m "$logfile" | cut -f1)

        if [ "$size_mb" -gt "$MAX_SIZE_MB" ]; then
            filename=$(basename "$logfile")
            timestamp=$(date +%Y%m%d_%H%M%S)

            echo "Rotating ${filename} (${size_mb}MB)"

            # Compress and rename
            gzip -c "$logfile" > "${logfile}.${timestamp}.gz"

            # Truncate original (keep file handle valid for running processes)
            > "$logfile"

            echo "✓ Rotated ${filename}"
        fi
    fi
done

# Clean up old rotated logs (keep only KEEP_COUNT per base name)
echo ""
echo "Cleaning up old rotated logs..."

for logfile in "${LOGS_DIR}"/*.log; do
    if [ -f "$logfile" ]; then
        base=$(basename "$logfile")

        # Find all rotated versions and sort by date (newest first)
        rotated_files=($(ls -t "${logfile}".*.gz 2>/dev/null || true))

        # Delete files beyond KEEP_COUNT
        if [ ${#rotated_files[@]} -gt $KEEP_COUNT ]; then
            for ((i=KEEP_COUNT; i<${#rotated_files[@]}; i++)); do
                echo "Removing old rotation: ${rotated_files[$i]}"
                rm "${rotated_files[$i]}"
            done
        fi
    fi
done

echo ""
