# Health check ping every 5 minutes (for monitoring dashboards)
*/5 * * * * curl -s http://localhost:8000/health/ingestion > /dev/null 2>&1 || echo "$(date): Health check failed" >> /Volumes/MacBackup/TrackFraudProject/logs/cron.log

